// dashboards/claude/golden_signals.jsonnet
local grafana   = import 'grafonnet/grafana.libsonnet';
local dashboard = grafana.dashboard;
local ts        = grafana.timeseriesPanel;    // Grafana 8+ native panel
local stat      = grafana.statPanel;
local table     = grafana.tablePanel;
local vars      = import '../lib/variables.libsonnet';
local prom      = grafana.target.prometheus;

// ── Panel builders ────────────────────────────────────────────────────────────

local latencyPanel = ts.new(
  title='Request Latency',
  datasource='$datasource',
).addTargets([
  prom.target(
    'histogram_quantile(0.50, sum by (le)(rate(claude_api_request_duration_seconds_bucket{feature=~"$feature"}[$interval])))',
    legendFormat='p50',
  ),
  prom.target(
    'histogram_quantile(0.99, sum by (le)(rate(claude_api_request_duration_seconds_bucket{feature=~"$feature"}[$interval])))',
    legendFormat='p99',
  ),
  prom.target(
    'histogram_quantile(0.999, sum by (le)(rate(claude_api_request_duration_seconds_bucket{feature=~"$feature"}[$interval])))',
    legendFormat='p99.9',
  ),
]) + {
  fieldConfig+: { defaults+: { unit: 's', custom+: { thresholdsStyle: { mode: 'line' } } } },
  options+: { tooltip: { mode: 'multi' } },
};

local requestRatePanel = ts.new(
  title='Request Rate',
  datasource='$datasource',
).addTarget(prom.target(
  'sum by (feature)(rate(claude_api_request_total{feature=~"$feature"}[$interval]))',
  legendFormat='{{feature}}',
)) + { fieldConfig+: { defaults+: { unit: 'reqps' } } };

local errorRatePanel = ts.new(
  title='Error Rate by Category',
  datasource='$datasource',
).addTarget(prom.target(
  'sum by (error_category)(rate(claude_api_error_total{feature=~"$feature"}[$interval]))',
  legendFormat='{{error_category}}',
)) + { fieldConfig+: { defaults+: { unit: 'reqps' }, overrides: [
  { matcher: { id: 'byName', options: 'rate_limit' }, properties: [{ id: 'color', value: { fixedColor: 'orange', mode: 'fixed' } }] },
  { matcher: { id: 'byName', options: 'timeout' }, properties: [{ id: 'color', value: { fixedColor: 'red', mode: 'fixed' } }] },
] } };

local activeRequestsPanel = stat.new(
  title='Active Requests',
  datasource='$datasource',
).addTarget(prom.target(
  'sum(claude_active_requests{feature=~"$feature"})',
  instant=true,
));

local circuitBreakerPanel = table.new(
  title='Circuit Breaker State',
  datasource='$datasource',
).addTarget(prom.target(
  'claude_circuit_breaker_state',
  instant=true,
  legendFormat='',
));

// ── Dashboard assembly ────────────────────────────────────────────────────────

dashboard.new(
  title='Claude — Golden Signals',
  uid='claude-golden-signals',
  tags=['claude', 'observability', 'on-call'],
  time_from='now-3h',
  refresh='30s',
  schemaVersion=36,
  editable=false,
)
.addTemplates([vars.datasource, vars.feature, vars.model, vars.interval])
.addPanels([
  latencyPanel     { gridPos: { x: 0,  y: 0, w: 12, h: 8 } },
  requestRatePanel { gridPos: { x: 12, y: 0, w: 12, h: 8 } },
  errorRatePanel   { gridPos: { x: 0,  y: 8, w: 12, h: 8 } },
  activeRequestsPanel { gridPos: { x: 12, y: 8, w: 6,  h: 4 } },
  circuitBreakerPanel { gridPos: { x: 18, y: 8, w: 6,  h: 8 } },
])

// dashboards/claude/cost_overview.jsonnet
local grafana   = import 'grafonnet/grafana.libsonnet';
local dashboard = grafana.dashboard;
local ts        = grafana.timeseriesPanel;
local stat      = grafana.statPanel;
local barchart  = grafana.barChartPanel;
local vars      = import '../lib/variables.libsonnet';
local prom      = grafana.target.prometheus;

// Total cost today (stat panel — big number)
local dailyCostPanel = stat.new(
  title='Cost Today (USD)',
  datasource='$datasource',
).addTarget(prom.target(
  |||
    sum(
      increase(claude_input_tokens_total[24h])  / 1e6 * on(model) group_left()
        label_replace(vector(3.0),  "model", "claude-sonnet-5", "", "")
      +
      increase(claude_output_tokens_total[24h]) / 1e6 * on(model) group_left()
        label_replace(vector(15.0), "model", "claude-sonnet-5", "", "")
    )
  |||,
  instant=true,
)) + { fieldConfig+: { defaults+: { unit: 'currencyUSD', decimals: 2 } } };

// Token rate (input vs output) — time series
local tokenRatePanel = ts.new(
  title='Token Rate — Input vs Output',
  datasource='$datasource',
).addTargets([
  prom.target(
    'sum(rate(claude_input_tokens_total{feature=~"$feature"}[$interval]))',
    legendFormat='input tokens/s',
  ),
  prom.target(
    'sum(rate(claude_output_tokens_total{feature=~"$feature"}[$interval]))',
    legendFormat='output tokens/s',
  ),
]) + { fieldConfig+: { defaults+: { unit: 'short' } } };

// Cache effectiveness (ratio)
local cachePanel = ts.new(
  title='Prompt Cache Hit Ratio',
  datasource='$datasource',
).addTarget(prom.target(
  |||
    sum(rate(claude_cache_read_tokens_total[$interval]))
    /
    (sum(rate(claude_input_tokens_total[$interval])) + 1e-9)
  |||,
  legendFormat='cache hit ratio',
)) + { fieldConfig+: { defaults+: { unit: 'percentunit', min: 0, max: 1 } } };

// Cost by feature (bar chart)
local costByFeaturePanel = barchart.new(
  title='Cost This Week by Feature',
  datasource='$datasource',
).addTarget(prom.target(
  |||
    sort_desc(sum by (feature)(
      increase(claude_input_tokens_total[7d])  / 1e6 * 3  +
      increase(claude_output_tokens_total[7d]) / 1e6 * 15
    ))
  |||,
  legendFormat='{{feature}}',
  instant=true,
));

dashboard.new(
  title='Claude — Cost Overview',
  uid='claude-cost-overview',
  tags=['claude', 'cost', 'observability'],
  time_from='now-7d',
  refresh='5m',
  schemaVersion=36,
  editable=false,
)
.addTemplates([vars.datasource, vars.feature, vars.model])
.addPanels([
  dailyCostPanel    { gridPos: { x: 0,  y: 0, w: 6,  h: 4 } },
  cachePanel        { gridPos: { x: 6,  y: 0, w: 18, h: 4 } },
  tokenRatePanel    { gridPos: { x: 0,  y: 4, w: 12, h: 8 } },
  costByFeaturePanel { gridPos: { x: 12, y: 4, w: 12, h: 8 } },
])

// dashboards/claude/quality_signals.jsonnet
local grafana   = import 'grafonnet/grafana.libsonnet';
local dashboard = grafana.dashboard;
local ts        = grafana.timeseriesPanel;
local stat      = grafana.statPanel;
local gauge     = grafana.gaugePanel;
local vars      = import '../lib/variables.libsonnet';
local prom      = grafana.target.prometheus;

// Eval score p50 — rolling time series
local qualityScorePanel = ts.new(
  title='Eval Score — p50 / p10 (LLM-as-Judge)',
  datasource='$datasource',
).addTargets([
  prom.target(
    'histogram_quantile(0.50, sum by (le, feature)(rate(claude_quality_score_bucket{feature=~"$feature"}[$interval])))',
    legendFormat='p50 {{feature}}',
  ),
  prom.target(
    'histogram_quantile(0.10, sum by (le, feature)(rate(claude_quality_score_bucket{feature=~"$feature"}[$interval])))',
    legendFormat='p10 {{feature}}',
  ),
]) + { fieldConfig+: { defaults+: { unit: 'percentunit', min: 0, max: 1,
  thresholds: { mode: 'absolute', steps: [
    { value: 0,    color: 'red' },
    { value: 0.5,  color: 'orange' },
    { value: 0.7,  color: 'yellow' },
    { value: 0.85, color: 'green' },
  ] },
} } };

// Format compliance rate
local compliancePanel = ts.new(
  title='Format Compliance Rate',
  datasource='$datasource',
).addTarget(prom.target(
  |||
    sum by (feature)(rate(claude_format_compliance_total{result="ok",feature=~"$feature"}[$interval]))
    /
    sum by (feature)(rate(claude_format_compliance_total{feature=~"$feature"}[$interval]))
  |||,
  legendFormat='{{feature}}',
)) + { fieldConfig+: { defaults+: { unit: 'percentunit', min: 0, max: 1 } } };

// User satisfaction gauge
local satisfactionPanel = gauge.new(
  title='User Satisfaction',
  datasource='$datasource',
).addTarget(prom.target(
  'avg(claude_user_satisfaction_ratio{feature=~"$feature"})',
  instant=true,
)) + { fieldConfig+: { defaults+: { unit: 'percentunit', min: 0, max: 1,
  thresholds: { mode: 'absolute', steps: [
    { value: 0,    color: 'red' },
    { value: 0.55, color: 'orange' },
    { value: 0.70, color: 'green' },
  ] },
} } };

// Eval drift delta
local driftPanel = stat.new(
  title='Eval Drift (vs Baseline)',
  datasource='$datasource',
).addTarget(prom.target(
  'avg(claude_eval_drift{feature=~"$feature"})',
  instant=true,
)) + { fieldConfig+: { defaults+: { unit: 'short', decimals: 3 } } };

// Semantic drift
local semanticDriftPanel = ts.new(
  title='Semantic Drift (Cosine Distance)',
  datasource='$datasource',
).addTarget(prom.target(
  'claude_semantic_drift_cosine{feature=~"$feature"}',
  legendFormat='{{feature}}',
)) + { fieldConfig+: { defaults+: { unit: 'short', min: 0,
  thresholds: { mode: 'absolute', steps: [
    { value: 0,    color: 'green' },
    { value: 0.10, color: 'yellow' },
    { value: 0.15, color: 'red' },
  ] },
} } };

dashboard.new(
  title='Claude — Quality Signals',
  uid='claude-quality-signals',
  tags=['claude', 'quality', 'observability'],
  time_from='now-24h',
  refresh='1m',
  schemaVersion=36,
  editable=false,
)
.addTemplates([vars.datasource, vars.feature, vars.model, vars.interval])
.addPanels([
  qualityScorePanel  { gridPos: { x: 0,  y: 0, w: 12, h: 8 } },
  compliancePanel    { gridPos: { x: 12, y: 0, w: 12, h: 8 } },
  satisfactionPanel  { gridPos: { x: 0,  y: 8, w: 6,  h: 8 } },
  driftPanel         { gridPos: { x: 6,  y: 8, w: 6,  h: 4 } },
  semanticDriftPanel { gridPos: { x: 12, y: 8, w: 12, h: 8 } },
])

// Add alert threshold annotation to a time-series panel
local latencyPanel = ts.new(...)
  .addTarget(...)
  + {
  fieldConfig+: {
    defaults+: {
      thresholds+: {
        mode: 'absolute',
        steps: [
          { value: 0,     color: 'green'  },
          { value: 5.0,   color: 'yellow' },  // 5s warning
          { value: 30.0,  color: 'red'    },  // 30s page
        ],
      },
      custom+: {
        thresholdsStyle: { mode: 'line+area' },
      },
    },
  },
};
